@tailwind base;
@tailwind components;
@tailwind utilities;

/* LIGHT MODE */
:root {
  --button-outline: rgba(0,0,0, .10);
  --badge-outline: rgba(0,0,0, .05);
  --opaque-button-border-intensity: -8;
  --elevate-1: rgba(0,0,0, .03);
  --elevate-2: rgba(0,0,0, .08);
  --background: 0 0% 100%;
  --foreground: 220 15% 12%;
  --border: 220 12% 92%;
  --card: 220 8% 98%;
  --card-foreground: 220 15% 12%;
  --card-border: 220 10% 95%;
  --sidebar: 220 10% 96%;
  --sidebar-foreground: 220 15% 12%;
  --sidebar-border: 220 12% 93%;
  --sidebar-primary: 215 77% 20%;
  --sidebar-primary-foreground: 215 20% 98%;
  --sidebar-accent: 220 12% 92%;
  --sidebar-accent-foreground: 220 15% 18%;
  --sidebar-ring: 221 91% 60%;
  --popover: 220 12% 94%;
  --popover-foreground: 220 15% 12%;
  --popover-border: 220 12% 91%;
  --primary: 215 77% 20%;
  --primary-foreground: 215 20% 98%;
  --secondary: 221 91% 60%;
  --secondary-foreground: 221 10% 12%;
  --muted: 220 18% 88%;
  --muted-foreground: 220 12% 28%;
  --accent: 188 95% 42%;
